import { createClient } from "@supabase/supabase-js";

const STORAGE_KEY = "nexo-app-data-v4";
const SUPABASE_URL = import.meta.env.VITE_SUPABASE_URL;
const SUPABASE_KEY = import.meta.env.VITE_SUPABASE_PUBLISHABLE_KEY;
const cloudConfigured = Boolean(SUPABASE_URL && SUPABASE_KEY);
const supabase = cloudConfigured ? createClient(SUPABASE_URL, SUPABASE_KEY, {
  auth: { persistSession: true, autoRefreshToken: true, detectSessionInUrl: true }
}) : null;
let currentUser = null;
let cloudTimer = null;
let cloudBusy = false;
let authMode = "login";
const LEGACY_KEYS = ["nexo-app-data-v3-2", "nexo-app-data-v3", "nexo-app-data-v1"];
const AREAS = ["Pessoal", "Revenda de carros", "Impressão 3D"];

const defaultCategories = [
  {id:"inc_salary",name:"Salário",icon:"💼",type:"income",area:"Pessoal",monthlyBudget:0,system:true},
  {id:"inc_other",name:"Outras receitas",icon:"＋",type:"income",area:"Pessoal",monthlyBudget:0,system:true},
  {id:"inc_cars",name:"Venda de veículos",icon:"🚘",type:"income",area:"Revenda de carros",monthlyBudget:0,system:true},
  {id:"inc_3d",name:"Vendas de produtos",icon:"📦",type:"income",area:"Impressão 3D",monthlyBudget:0,system:true},
  {id:"exp_food",name:"Alimentação",icon:"🍽",type:"expense",area:"Pessoal",monthlyBudget:0,system:true},
  {id:"exp_transport",name:"Transporte e combustível",icon:"⛽",type:"expense",area:"Pessoal",monthlyBudget:0,system:true},
  {id:"exp_leisure",name:"Lazer",icon:"🎮",type:"expense",area:"Pessoal",monthlyBudget:0,system:true},
  {id:"exp_subscriptions",name:"Assinaturas",icon:"◉",type:"expense",area:"Pessoal",monthlyBudget:0,system:true},
  {id:"exp_studies",name:"Escola e estudos",icon:"📚",type:"expense",area:"Pessoal",monthlyBudget:0,system:true},
  {id:"exp_personal_other",name:"Outros gastos",icon:"•••",type:"expense",area:"Pessoal",monthlyBudget:0,system:true},
  {id:"exp_car_purchase",name:"Compra de veículos",icon:"🔑",type:"expense",area:"Revenda de carros",monthlyBudget:0,system:true},
  {id:"exp_car_maintenance",name:"Manutenção e peças",icon:"🔧",type:"expense",area:"Revenda de carros",monthlyBudget:0,system:true},
  {id:"exp_car_docs",name:"Documentação",icon:"📄",type:"expense",area:"Revenda de carros",monthlyBudget:0,system:true},
  {id:"exp_car_ads",name:"Anúncios e preparação",icon:"📣",type:"expense",area:"Revenda de carros",monthlyBudget:0,system:true},
  {id:"exp_filament",name:"Filamento",icon:"🧵",type:"expense",area:"Impressão 3D",monthlyBudget:0,system:true},
  {id:"exp_packaging",name:"Embalagens",icon:"📦",type:"expense",area:"Impressão 3D",monthlyBudget:0,system:true},
  {id:"exp_marketplace",name:"Taxas do marketplace",icon:"🛒",type:"expense",area:"Impressão 3D",monthlyBudget:0,system:true},
  {id:"exp_marketing",name:"Marketing e afiliados",icon:"📈",type:"expense",area:"Impressão 3D",monthlyBudget:0,system:true},
  {id:"exp_energy",name:"Energia",icon:"⚡",type:"expense",area:"Impressão 3D",monthlyBudget:0,system:true},
  {id:"exp_equipment",name:"Equipamentos e manutenção",icon:"🖨",type:"expense",area:"Impressão 3D",monthlyBudget:0,system:true}
];
const defaultAccounts = [
  {id:"acc_personal",name:"Conta pessoal",icon:"🏦",type:"Banco",area:"Pessoal",liquidity:"free",openingBalance:0,system:true},
  {id:"acc_cash",name:"Dinheiro em espécie",icon:"💵",type:"Dinheiro",area:"Pessoal",liquidity:"free",openingBalance:0,system:true},
  {id:"acc_reserve",name:"Reserva",icon:"🛡",type:"Reserva",area:"Pessoal",liquidity:"reserved",openingBalance:0,system:true},
  {id:"acc_cars",name:"Caixa da revenda",icon:"🚘",type:"Caixa do negócio",area:"Revenda de carros",liquidity:"free",openingBalance:0,system:true},
  {id:"acc_3d",name:"Caixa da impressão 3D",icon:"🖨",type:"Caixa do negócio",area:"Impressão 3D",liquidity:"free",openingBalance:0,system:true},
  {id:"acc_marketplace",name:"Saldo em marketplaces",icon:"🛒",type:"Carteira digital",area:"Impressão 3D",liquidity:"reserved",openingBalance:0,system:true}
];
const emptyState = {transactions:[],categories:defaultCategories,accounts:defaultAccounts,transfers:[],tasks:[],assets:[],debts:[],snapshots:[],wealthGoal:{target:0,deadline:""},theme:"light"};
let state = loadState();

function uid(){return Date.now().toString(36)+Math.random().toString(36).slice(2)}
function clone(v){return JSON.parse(JSON.stringify(v))}
function brl(v){return Number(v||0).toLocaleString("pt-BR",{style:"currency",currency:"BRL"})}
function todayISO(){return new Date().toISOString().slice(0,10)}
function monthISO(){return new Date().toISOString().slice(0,7)}
function currentTime(){return new Date().toLocaleTimeString("pt-BR",{hour:"2-digit",minute:"2-digit",hour12:false})}
function formatDate(d){return d?new Date(d+"T12:00:00").toLocaleDateString("pt-BR"):"—"}
function formatMonth(m){if(!m)return"—";const [y,mo]=m.split("-");return new Date(Number(y),Number(mo)-1,1).toLocaleDateString("pt-BR",{month:"short",year:"2-digit"})}
function sum(list,fn){return list.reduce((a,x)=>a+Number(fn(x)||0),0)}
function esc(s=""){return String(s).replace(/[&<>"']/g,c=>({"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#039;"}[c]))}
function monthKey(d){return d?d.slice(0,7):monthISO()}
function dt(item){return new Date(`${item.date||todayISO()}T${item.time||"00:00"}:00`)}

function normalize(data={}){
  const n={...clone(emptyState),...data};
  n.categories=Array.isArray(data.categories)&&data.categories.length?data.categories:clone(defaultCategories);
  n.accounts=Array.isArray(data.accounts)&&data.accounts.length?data.accounts:clone(defaultAccounts);
  n.transactions=Array.isArray(data.transactions)?data.transactions:[];
  n.transfers=Array.isArray(data.transfers)?data.transfers:[];
  n.tasks=Array.isArray(data.tasks)?data.tasks:[];
  n.assets=Array.isArray(data.assets)?data.assets:[];
  n.debts=Array.isArray(data.debts)?data.debts:[];
  n.snapshots=Array.isArray(data.snapshots)?data.snapshots:[];
  if(!data.wealthGoal&&Array.isArray(data.goals)&&data.goals.length){n.wealthGoal={target:Number(data.goals[0].target||0),deadline:data.goals[0].deadline||""}}
  n.wealthGoal=n.wealthGoal||{target:0,deadline:""};
  n.transactions=n.transactions.map(t=>({...t,id:t.id||uid(),categoryId:t.categoryId||null,accountId:t.accountId||null,time:t.time||"00:00",value:Number(t.value||0)}));
  n.accounts=n.accounts.map(a=>({...a,id:a.id||uid(),openingBalance:Number(a.openingBalance||0),liquidity:a.liquidity||((a.type==="Reserva"||a.type==="Carteira digital")?"reserved":"free")}));
  n.categories=n.categories.map(c=>({...c,id:c.id||uid(),monthlyBudget:Number(c.monthlyBudget||0)}));
  n.assets=n.assets.map(a=>({...a,id:a.id||uid(),purchaseValue:Number(a.purchaseValue||0),currentValue:Number(a.currentValue||0)}));
  n.debts=n.debts.map(d=>({...d,id:d.id||uid(),originalValue:Number(d.originalValue||0),currentBalance:Number(d.currentBalance||0),installment:Number(d.installment||0),interest:Number(d.interest||0)}));
  n.snapshots=n.snapshots.map(s=>({...s,id:s.id||uid(),netWorth:Number(s.netWorth||0),cash:Number(s.cash||0),assets:Number(s.assets||0),debts:Number(s.debts||0)})).sort((a,b)=>a.month.localeCompare(b.month));
  return n;
}
function loadState(){try{let raw=localStorage.getItem(STORAGE_KEY);if(!raw){for(const k of LEGACY_KEYS){raw=localStorage.getItem(k);if(raw)break}}const n=normalize(raw?JSON.parse(raw):{});localStorage.setItem(STORAGE_KEY,JSON.stringify(n));return n}catch{return normalize({})}}
function userStorageKey(userId){return `${STORAGE_KEY}:${userId}`}
function loadUserLocalState(userId){try{const raw=localStorage.getItem(userStorageKey(userId));return raw?normalize(JSON.parse(raw)):null}catch{return null}}
function save(syncCloud=true){
  localStorage.setItem(currentUser?userStorageKey(currentUser.id):STORAGE_KEY,JSON.stringify(state));
  if(syncCloud)scheduleCloudSync();
}
function hasMeaningfulData(s){return Boolean(s.transactions.length||s.transfers.length||s.tasks.length||s.assets.length||s.debts.length||s.snapshots.length||s.accounts.some(a=>Number(a.openingBalance)!==0)||Number(s.wealthGoal?.target)>0)}
function setSyncStatus(status,detail=""){
  const top=document.getElementById("topSyncStatus"),side=document.getElementById("sidebarSyncStatus"),settings=document.getElementById("cloudSyncDetails");
  const map={synced:"Sincronizado",syncing:"Salvando...",error:"Erro na nuvem",offline:"Offline",local:"Somente local"};
  [top].forEach(el=>{if(el){el.textContent=map[status]||status;el.className=`sync-badge ${status}`}});
  if(side)side.textContent=map[status]||status;if(settings)settings.textContent=detail||(status==="synced"?`Última sincronização: ${new Date().toLocaleString("pt-BR")}`:map[status]||status);
}
function scheduleCloudSync(){
  if(!currentUser||!supabase)return;
  clearTimeout(cloudTimer);setSyncStatus(navigator.onLine?"syncing":"offline");
  cloudTimer=setTimeout(()=>syncCloudNow(),700);
}
async function syncCloudNow(){
  if(!currentUser||!supabase||cloudBusy)return false;
  if(!navigator.onLine){setSyncStatus("offline","Dados salvos neste aparelho. A nuvem será atualizada quando a internet voltar.");return false}
  cloudBusy=true;setSyncStatus("syncing");
  const {error}=await supabase.from("user_app_state").upsert({user_id:currentUser.id,data:state,updated_at:new Date().toISOString()},{onConflict:"user_id"});
  cloudBusy=false;
  if(error){console.error(error);setSyncStatus("error",`Falha ao sincronizar: ${error.message}`);return false}
  setSyncStatus("synced");return true;
}
async function loadCloudState(user){
  setSyncStatus("syncing","Carregando seus dados da nuvem...");
  const userLocal=loadUserLocalState(user.id);
  const {data,error}=await supabase.from("user_app_state").select("data,updated_at").eq("user_id",user.id).maybeSingle();
  if(error)throw error;
  if(data?.data){
    state=normalize(data.data);
    save(false);
    setSyncStatus("synced",`Dados carregados da nuvem. Última atualização: ${data.updated_at?new Date(data.updated_at).toLocaleString("pt-BR"):"agora"}`);
  }else{
    const migratedUser=localStorage.getItem("nexo-cloud-migrated-user");
    if(userLocal)state=userLocal;
    else if(!migratedUser&&hasMeaningfulData(state)){localStorage.setItem("nexo-cloud-migrated-user",user.id)}
    else state=normalize({});
    save(false);
    await syncCloudNow();
  }
  renderAll();
}
function showAuth(){document.getElementById("authScreen").classList.remove("hidden");document.getElementById("appShell").classList.add("app-hidden")}
function showApp(){document.getElementById("authScreen").classList.add("hidden");document.getElementById("appShell").classList.remove("app-hidden")}
function authMessage(message,type="error"){const el=document.getElementById("authMessage");el.textContent=message;el.className=`auth-message ${type}`}
function setAuthMode(mode){authMode=mode;document.getElementById("showLogin").classList.toggle("active",mode==="login");document.getElementById("showSignup").classList.toggle("active",mode==="signup");document.getElementById("authTitle").textContent=mode==="login"?"Entrar na sua conta":"Criar sua conta";document.getElementById("authSubmit").textContent=mode==="login"?"Entrar":"Criar conta";document.getElementById("authPassword").autocomplete=mode==="login"?"current-password":"new-password";authMessage("")}
async function enterApp(user){
  currentUser=user;document.getElementById("cloudUserEmail").textContent=user.email||"Conta conectada";showApp();
  try{await loadCloudState(user)}catch(error){console.error(error);state=normalize(loadState());renderAll();setSyncStatus("error",`Não foi possível carregar a nuvem: ${error.message}`)}
}
async function initializeCloud(){
  if(!cloudConfigured){document.getElementById("configWarning").classList.remove("hidden");authMessage("Configure VITE_SUPABASE_URL e VITE_SUPABASE_PUBLISHABLE_KEY na Vercel.");return}
  const {data:{session},error}=await supabase.auth.getSession();
  if(error)authMessage(error.message);
  if(session?.user)await enterApp(session.user);else showAuth();
  supabase.auth.onAuthStateChange((event,session)=>{
    setTimeout(async()=>{
      if(event==="PASSWORD_RECOVERY"){const password=prompt("Digite sua nova senha (mínimo 6 caracteres):");if(password){const {error}=await supabase.auth.updateUser({password});alert(error?error.message:"Senha atualizada.")}}
      if(session?.user&&session.user.id!==currentUser?.id)await enterApp(session.user);
      if(!session){currentUser=null;state=normalize({});renderAll();showAuth();setSyncStatus("local")}
    },0);
  });
}

function category(id){return state.categories.find(x=>x.id===id)}
function account(id){return state.accounts.find(x=>x.id===id)}
function asset(id){return state.assets.find(x=>x.id===id)}
function categoryName(id){return category(id)?.name||"Sem categoria"}
function accountName(id){return account(id)?.name||"Sem conta"}
function accountBalance(a){const tx=sum(state.transactions.filter(t=>t.accountId===a.id),t=>t.type==="income"?t.value:-t.value);const incoming=sum(state.transfers.filter(t=>t.toAccountId===a.id),t=>t.value);const outgoing=sum(state.transfers.filter(t=>t.fromAccountId===a.id),t=>t.value);return Number(a.openingBalance||0)+tx+incoming-outgoing}
function cashTotal(){return sum(state.accounts,accountBalance)}
function freeCash(){return sum(state.accounts.filter(a=>a.liquidity==="free"),accountBalance)}
function reservedCash(){return sum(state.accounts.filter(a=>a.liquidity==="reserved"),accountBalance)}
function assetsTotal(){return sum(state.assets,a=>a.currentValue)}
function debtsTotal(){return sum(state.debts,d=>d.currentBalance)}
function netWorth(){return cashTotal()+assetsTotal()-debtsTotal()}
function monthTransactions(m=monthISO()){return state.transactions.filter(t=>monthKey(t.date)===m)}
function monthResult(m=monthISO()){const tx=monthTransactions(m);return sum(tx.filter(t=>t.type==="income"),t=>t.value)-sum(tx.filter(t=>t.type==="expense"),t=>t.value)}
function categorySpent(c,m=monthISO()){return sum(monthTransactions(m).filter(t=>t.type===c.type&&t.categoryId===c.id),t=>t.value)}
function snapshotGrowth(){if(!state.snapshots.length)return null;const previous=state.snapshots[state.snapshots.length-1];return netWorth()-previous.netWorth}
function wealthParts(){return [{name:"Dinheiro livre",value:freeCash(),icon:"💵"},{name:"Reservado",value:reservedCash(),icon:"🛡"},{name:"Ativos",value:assetsTotal(),icon:"◆"},{name:"Dívidas",value:-debtsTotal(),icon:"−"}]}

function setTheme(t){state.theme=t;document.body.classList.toggle("dark",t==="dark");save()}
function openPage(id){document.querySelectorAll(".page").forEach(x=>x.classList.remove("active"));document.querySelectorAll(".nav-item").forEach(x=>x.classList.remove("active"));document.getElementById(id)?.classList.add("active");document.querySelector(`[data-page="${id}"]`)?.classList.add("active");const names={dashboard:"Visão geral",finances:"Finanças",accounts:"Contas",wealth:"Patrimônio",routine:"Rotina",settings:"Ajustes"};document.getElementById("pageTitle").textContent=names[id]||"NEXO";renderAll();window.scrollTo({top:0,behavior:"smooth"})}
function showModal(html){document.getElementById("modal").innerHTML=html;document.getElementById("modalBackdrop").classList.remove("hidden")}
function closeModal(){document.getElementById("modalBackdrop").classList.add("hidden")}
function modalHeader(eyebrow,title){return `<div class="modal-header"><div><p class="eyebrow">${eyebrow}</p><h3>${title}</h3></div><button class="icon-button" data-close-modal>✕</button></div>`}

function categoryOptions(type,area,selected=""){const list=state.categories.filter(c=>c.type===type&&c.area===area).sort((a,b)=>a.name.localeCompare(b.name,"pt-BR"));return `<option value="">Sem categoria</option>${list.map(c=>`<option value="${c.id}" ${c.id===selected?"selected":""}>${esc(c.icon)} ${esc(c.name)}</option>`).join("")}`}
function accountOptions(area,selected=""){const list=state.accounts.slice().sort((a,b)=>(a.area===area?-1:1)-(b.area===area?-1:1)||a.name.localeCompare(b.name,"pt-BR"));return list.map(a=>`<option value="${a.id}" ${a.id===selected?"selected":""}>${esc(a.icon)} ${esc(a.name)} · ${brl(accountBalance(a))}</option>`).join("")}
function areaOptions(selected=""){return AREAS.map(a=>`<option ${a===selected?"selected":""}>${a}</option>`).join("")}

function transactionForm(){showModal(`${modalHeader("Fluxo financeiro","Novo lançamento")}<form id="transactionForm"><div class="form-grid"><div class="field"><label>Tipo</label><select id="txType" name="type"><option value="expense">Despesa</option><option value="income">Receita</option></select></div><div class="field"><label>Área</label><select id="txArea" name="area">${areaOptions("Pessoal")}</select></div><div class="field full"><label>Conta ou caixa</label><select id="txAccount" name="accountId" required></select><small>Onde o dinheiro entrou ou de onde saiu.</small></div><div class="field full"><label>Categoria</label><select id="txCategory" name="categoryId"></select></div><div class="field full"><label>Descrição</label><input name="description" required placeholder="Ex.: Compra de filamento"></div><div class="field"><label>Valor</label><input name="value" type="number" min="0.01" step="0.01" required></div><div class="field"><label>Data</label><input name="date" type="date" value="${todayISO()}" required></div><div class="field"><label>Hora</label><input name="time" type="time" value="${currentTime()}" required></div></div><div class="modal-actions"><button type="button" class="ghost-button" data-close-modal>Cancelar</button><button class="primary-button">Salvar</button></div></form>`);const type=document.getElementById("txType"),area=document.getElementById("txArea"),cat=document.getElementById("txCategory"),acc=document.getElementById("txAccount");const refresh=()=>{cat.innerHTML=categoryOptions(type.value,area.value);acc.innerHTML=accountOptions(area.value)};type.onchange=refresh;area.onchange=refresh;refresh();document.getElementById("transactionForm").onsubmit=e=>{e.preventDefault();const d=Object.fromEntries(new FormData(e.currentTarget));state.transactions.unshift({id:uid(),type:d.type,area:d.area,accountId:d.accountId,categoryId:d.categoryId||null,description:d.description.trim(),value:Number(d.value),date:d.date,time:d.time,createdAt:Date.now()});save();closeModal();renderAll()}}
function categoryForm(c=null){showModal(`${modalHeader("Orçamento",`${c?"Editar":"Nova"} categoria`)}<form id="categoryForm"><div class="form-grid"><div class="field"><label>Ícone</label><input name="icon" maxlength="4" value="${esc(c?.icon||"◫")}"></div><div class="field"><label>Tipo</label><select name="type"><option value="expense" ${c?.type!=="income"?"selected":""}>Gasto</option><option value="income" ${c?.type==="income"?"selected":""}>Receita</option></select></div><div class="field full"><label>Nome</label><input name="name" value="${esc(c?.name||"")}" required></div><div class="field"><label>Área</label><select name="area">${areaOptions(c?.area||"Pessoal")}</select></div><div class="field"><label>Limite/meta mensal</label><input name="monthlyBudget" type="number" min="0" step="0.01" value="${Number(c?.monthlyBudget||0)}"></div></div><div class="modal-actions"><button type="button" class="ghost-button" data-close-modal>Cancelar</button><button class="primary-button">Salvar</button></div></form>`);document.getElementById("categoryForm").onsubmit=e=>{e.preventDefault();const d=Object.fromEntries(new FormData(e.currentTarget));const p={icon:d.icon.trim()||"◫",name:d.name.trim(),type:d.type,area:d.area,monthlyBudget:Number(d.monthlyBudget||0)};if(c)Object.assign(c,p);else state.categories.push({id:uid(),...p,system:false});save();closeModal();renderAll()}}
function accountForm(a=null){showModal(`${modalHeader("Mapa do dinheiro",`${a?"Editar":"Nova"} conta ou caixa`)}<form id="accountForm"><div class="form-grid"><div class="field"><label>Ícone</label><input name="icon" maxlength="4" value="${esc(a?.icon||"◈")}"></div><div class="field"><label>Tipo</label><select name="type">${["Banco","Dinheiro","Reserva","Caixa do negócio","Carteira digital","Investimento","Outro"].map(x=>`<option ${x===a?.type?"selected":""}>${x}</option>`).join("")}</select></div><div class="field full"><label>Nome</label><input name="name" value="${esc(a?.name||"")}" required></div><div class="field"><label>Área</label><select name="area">${areaOptions(a?.area||"Pessoal")}</select></div><div class="field"><label>Disponibilidade</label><select name="liquidity"><option value="free" ${a?.liquidity!=="reserved"?"selected":""}>Dinheiro livre</option><option value="reserved" ${a?.liquidity==="reserved"?"selected":""}>Reservado/comprometido</option></select></div><div class="field full"><label>Saldo inicial</label><input name="openingBalance" type="number" step="0.01" value="${Number(a?.openingBalance||0)}" required><small>Valor existente antes dos lançamentos registrados no NEXO.</small></div></div><div class="modal-actions"><button type="button" class="ghost-button" data-close-modal>Cancelar</button><button class="primary-button">Salvar</button></div></form>`);document.getElementById("accountForm").onsubmit=e=>{e.preventDefault();const d=Object.fromEntries(new FormData(e.currentTarget));const p={icon:d.icon.trim()||"◈",name:d.name.trim(),type:d.type,area:d.area,liquidity:d.liquidity,openingBalance:Number(d.openingBalance||0)};if(a)Object.assign(a,p);else state.accounts.push({id:uid(),...p,system:false});save();closeModal();renderAll()}}
function transferForm(){if(state.accounts.length<2)return alert("Cadastre pelo menos duas contas.");showModal(`${modalHeader("Movimentação interna","Transferir dinheiro")}<form id="transferForm"><div class="form-grid"><div class="field full"><label>Origem</label><select name="fromAccountId">${state.accounts.map(a=>`<option value="${a.id}">${esc(a.icon)} ${esc(a.name)} · ${brl(accountBalance(a))}</option>`).join("")}</select></div><div class="field full"><label>Destino</label><select name="toAccountId">${state.accounts.map((a,i)=>`<option value="${a.id}" ${i===1?"selected":""}>${esc(a.icon)} ${esc(a.name)} · ${brl(accountBalance(a))}</option>`).join("")}</select></div><div class="field"><label>Valor</label><input name="value" type="number" min="0.01" step="0.01" required></div><div class="field"><label>Descrição</label><input name="description" value="Transferência entre contas" required></div><div class="field"><label>Data</label><input name="date" type="date" value="${todayISO()}" required></div><div class="field"><label>Hora</label><input name="time" type="time" value="${currentTime()}" required></div><div class="field full"><div class="form-note">Transferência muda o local do dinheiro, mas não entra como receita nem despesa.</div></div></div><div class="modal-actions"><button type="button" class="ghost-button" data-close-modal>Cancelar</button><button class="primary-button">Transferir</button></div></form>`);document.getElementById("transferForm").onsubmit=e=>{e.preventDefault();const d=Object.fromEntries(new FormData(e.currentTarget));if(d.fromAccountId===d.toAccountId)return alert("Origem e destino precisam ser diferentes.");state.transfers.unshift({id:uid(),fromAccountId:d.fromAccountId,toAccountId:d.toAccountId,value:Number(d.value),description:d.description.trim(),date:d.date,time:d.time,createdAt:Date.now()});save();closeModal();renderAll()}}
function assetForm(a=null){showModal(`${modalHeader("Patrimônio",`${a?"Editar":"Novo"} ativo`)}<form id="assetForm"><div class="form-grid"><div class="field"><label>Ícone</label><input name="icon" maxlength="4" value="${esc(a?.icon||"◆")}"></div><div class="field"><label>Tipo</label><select name="type">${["Veículo em estoque","Equipamento","Estoque de materiais","Produto pronto","Valor a receber","Investimento","Outro bem"].map(x=>`<option ${x===a?.type?"selected":""}>${x}</option>`).join("")}</select></div><div class="field full"><label>Nome do ativo</label><input name="name" value="${esc(a?.name||"")}" required placeholder="Ex.: Fiat Strada em estoque"></div><div class="field"><label>Área</label><select name="area">${areaOptions(a?.area||"Revenda de carros")}</select></div><div class="field"><label>Data de aquisição</label><input name="date" type="date" value="${a?.date||todayISO()}"></div><div class="field"><label>Valor pago/investido</label><input name="purchaseValue" type="number" min="0" step="0.01" value="${Number(a?.purchaseValue||0)}"></div><div class="field"><label>Valor atual estimado</label><input name="currentValue" type="number" min="0" step="0.01" value="${Number(a?.currentValue||0)}" required></div><div class="field full"><label>Observações</label><textarea name="notes">${esc(a?.notes||"")}</textarea><small>Não cadastre dinheiro que já está nas contas, senão o patrimônio será contado duas vezes.</small></div></div><div class="modal-actions"><button type="button" class="ghost-button" data-close-modal>Cancelar</button><button class="primary-button">Salvar ativo</button></div></form>`);document.getElementById("assetForm").onsubmit=e=>{e.preventDefault();const d=Object.fromEntries(new FormData(e.currentTarget));const p={icon:d.icon.trim()||"◆",type:d.type,name:d.name.trim(),area:d.area,date:d.date,purchaseValue:Number(d.purchaseValue||0),currentValue:Number(d.currentValue||0),notes:d.notes.trim()};if(a)Object.assign(a,p);else state.assets.push({id:uid(),...p,createdAt:Date.now()});save();closeModal();renderAll()}}
function debtForm(d=null){showModal(`${modalHeader("Patrimônio",`${d?"Editar":"Nova"} dívida`)}<form id="debtForm"><div class="form-grid"><div class="field full"><label>Nome da dívida</label><input name="name" value="${esc(d?.name||"")}" required placeholder="Ex.: Financiamento do veículo"></div><div class="field"><label>Área</label><select name="area">${areaOptions(d?.area||"Pessoal")}</select></div><div class="field"><label>Ativo relacionado</label><select name="assetId"><option value="">Nenhum</option>${state.assets.map(a=>`<option value="${a.id}" ${a.id===d?.assetId?"selected":""}>${esc(a.name)}</option>`).join("")}</select></div><div class="field"><label>Valor original</label><input name="originalValue" type="number" min="0" step="0.01" value="${Number(d?.originalValue||0)}"></div><div class="field"><label>Saldo devedor atual</label><input name="currentBalance" type="number" min="0" step="0.01" value="${Number(d?.currentBalance||0)}" required></div><div class="field"><label>Parcela mensal</label><input name="installment" type="number" min="0" step="0.01" value="${Number(d?.installment||0)}"></div><div class="field"><label>Dia do vencimento</label><input name="dueDay" type="number" min="1" max="31" value="${d?.dueDay||""}"></div><div class="field"><label>Juros ao mês (%)</label><input name="interest" type="number" min="0" step="0.01" value="${Number(d?.interest||0)}"></div><div class="field full"><label>Observações</label><textarea name="notes">${esc(d?.notes||"")}</textarea></div></div><div class="modal-actions"><button type="button" class="ghost-button" data-close-modal>Cancelar</button><button class="primary-button">Salvar dívida</button></div></form>`);document.getElementById("debtForm").onsubmit=e=>{e.preventDefault();const x=Object.fromEntries(new FormData(e.currentTarget));const p={name:x.name.trim(),area:x.area,assetId:x.assetId||null,originalValue:Number(x.originalValue||0),currentBalance:Number(x.currentBalance||0),installment:Number(x.installment||0),dueDay:Number(x.dueDay||0),interest:Number(x.interest||0),notes:x.notes.trim()};if(d)Object.assign(d,p);else state.debts.push({id:uid(),...p,createdAt:Date.now()});save();closeModal();renderAll()}}
function goalForm(){const g=state.wealthGoal;showModal(`${modalHeader("Meta patrimonial","Definir objetivo")}<form id="goalForm"><div class="form-grid"><div class="field full"><label>Patrimônio desejado</label><input name="target" type="number" min="0" step="0.01" value="${Number(g.target||0)}" required></div><div class="field full"><label>Prazo</label><input name="deadline" type="date" value="${g.deadline||""}"></div><div class="field full"><div class="form-note">O progresso usa o patrimônio líquido calculado: dinheiro + ativos − dívidas.</div></div></div><div class="modal-actions"><button type="button" class="ghost-button" data-close-modal>Cancelar</button><button class="primary-button">Salvar meta</button></div></form>`);document.getElementById("goalForm").onsubmit=e=>{e.preventDefault();const d=Object.fromEntries(new FormData(e.currentTarget));state.wealthGoal={target:Number(d.target||0),deadline:d.deadline};save();closeModal();renderAll()}}
function taskForm(){showModal(`${modalHeader("Organização","Nova tarefa")}<form id="taskForm"><div class="form-grid"><div class="field full"><label>Tarefa</label><input name="title" required></div><div class="field"><label>Área</label><select name="category"><option>Pessoal</option><option>Escola</option><option>Oficina</option><option>Revenda de carros</option><option>Impressão 3D</option></select></div><div class="field"><label>Prioridade</label><select name="priority"><option value="high">Alta</option><option value="medium" selected>Média</option><option value="low">Baixa</option></select></div><div class="field"><label>Data</label><input name="date" type="date" value="${todayISO()}"></div><div class="field"><label>Hora</label><input name="time" type="time"></div><div class="field full"><label>Observações</label><textarea name="notes"></textarea></div></div><div class="modal-actions"><button type="button" class="ghost-button" data-close-modal>Cancelar</button><button class="primary-button">Salvar</button></div></form>`);document.getElementById("taskForm").onsubmit=e=>{e.preventDefault();const d=Object.fromEntries(new FormData(e.currentTarget));state.tasks.unshift({id:uid(),title:d.title.trim(),category:d.category,priority:d.priority,date:d.date,time:d.time,notes:d.notes.trim(),done:false,createdAt:Date.now()});save();closeModal();renderAll()}}

function manageCategories(){showModal(`${modalHeader("Orçamento","Gerenciar categorias")}<div class="history-list">${state.categories.slice().sort((a,b)=>a.area.localeCompare(b.area,"pt-BR")||a.name.localeCompare(b.name,"pt-BR")).map(c=>`<div class="history-item"><div><strong>${esc(c.icon)} ${esc(c.name)}</strong><small>${esc(c.area)} · ${c.type==="income"?"Receita":"Gasto"}</small></div><div><strong>${c.monthlyBudget?brl(c.monthlyBudget):"Sem limite/meta"}</strong><small>${c.type==="income"?"Meta mensal":"Limite mensal"}</small></div><div><button class="icon-button" data-edit-category="${c.id}">✎ Editar</button><button class="icon-button" data-delete-category="${c.id}">✕</button></div></div>`).join("")}</div><div class="modal-actions"><button class="primary-button" id="categoryFromManager">+ Nova categoria</button></div>`);document.getElementById("categoryFromManager").onclick=()=>categoryForm()}
function categoryHistory(c){const items=state.transactions.filter(t=>t.categoryId===c.id&&t.type===c.type).sort((a,b)=>dt(b)-dt(a));showModal(`${modalHeader(c.area,c.name)}<div class="history-summary"><div><span>Total</span><strong>${brl(sum(items,x=>x.value))}</strong></div><div><span>Lançamentos</span><strong>${items.length}</strong></div><div><span>Limite mensal</span><strong>${c.monthlyBudget?brl(c.monthlyBudget):"Sem limite"}</strong></div></div><div class="history-list">${items.length?items.map(x=>`<div class="history-item"><div><strong>${formatDate(x.date)}</strong><small>${x.time}</small></div><div><strong>${esc(x.description)}</strong><small>${esc(accountName(x.accountId))}</small></div><strong class="${x.type==="income"?"amount-income":"amount-expense"}">${x.type==="income"?"+":"-"} ${brl(x.value)}</strong></div>`).join(""):`<div class="empty">Nenhum lançamento nesta categoria.</div>`}</div>`)}
function accountHistory(a){const tx=state.transactions.filter(t=>t.accountId===a.id).map(t=>({...t,label:t.type==="income"?"Receita":"Despesa",signed:t.type==="income"?t.value:-t.value}));const tr=state.transfers.filter(t=>t.fromAccountId===a.id||t.toAccountId===a.id).map(t=>{const incoming=t.toAccountId===a.id;return {...t,label:incoming?`Recebido de ${accountName(t.fromAccountId)}`:`Enviado para ${accountName(t.toAccountId)}`,signed:incoming?t.value:-t.value}});const items=[...tx,...tr].sort((a,b)=>dt(b)-dt(a));showModal(`${modalHeader(a.area,a.name)}<div class="history-summary"><div><span>Saldo atual</span><strong>${brl(accountBalance(a))}</strong></div><div><span>Saldo inicial</span><strong>${brl(a.openingBalance)}</strong></div><div><span>Movimentações</span><strong>${items.length}</strong></div></div><div class="history-list">${items.length?items.map(x=>`<div class="history-item"><div><strong>${formatDate(x.date)}</strong><small>${x.time}</small></div><div><strong>${esc(x.description||"Transferência")}</strong><small>${esc(x.label)}</small></div><strong class="${x.signed>=0?"amount-income":"amount-expense"}">${x.signed>=0?"+":"-"} ${brl(Math.abs(x.signed))}</strong></div>`).join(""):`<div class="empty">Nenhuma movimentação.</div>`}</div>`)}

function taskHTML(t){const label={high:"Alta",medium:"Média",low:"Baixa"};return `<div class="task-card ${t.done?"done":""}"><div class="task-main"><button class="check-button ${t.done?"checked":""}" data-toggle-task="${t.id}">${t.done?"✓":""}</button><div><h4>${esc(t.title)}</h4><div class="task-meta">${esc(t.category)} · ${formatDate(t.date)} ${t.time?"· "+t.time:""}</div><div class="task-meta priority-${t.priority}">Prioridade ${label[t.priority]}</div></div></div><button class="icon-button" data-delete-task="${t.id}">✕</button></div>`}
function chartHTML(){if(!state.snapshots.length)return `<div class="empty">Salve uma fotografia mensal para iniciar o histórico.</div>`;const current={month:monthISO(),netWorth:netWorth(),current:true};let points=state.snapshots.filter(s=>s.month!==current.month).slice(-7);points.push(current);const max=Math.max(1,...points.map(p=>Math.max(0,p.netWorth)));return points.map(p=>`<div class="history-bar-wrap"><strong>${brl(p.netWorth)}</strong><div class="history-bar" style="height:${Math.max(4,Math.max(0,p.netWorth)/max*170)}px"></div><small>${formatMonth(p.month)}${p.current?"*":""}</small></div>`).join("")}
function goalHTML(){const g=state.wealthGoal;if(!g.target)return `<div class="empty">Defina uma meta patrimonial para acompanhar o progresso.</div>`;const current=netWorth(),pct=Math.max(0,Math.min(100,current/g.target*100)),missing=Math.max(0,g.target-current);return `<strong class="goal-number">${pct.toFixed(0)}%</strong><div class="progress"><span style="width:${pct}%"></span></div><div class="goal-meta"><span>Atual: ${brl(current)}</span><span>Meta: ${brl(g.target)}</span></div><div class="goal-meta"><span>Falta: ${brl(missing)}</span><span>${g.deadline?"Prazo: "+formatDate(g.deadline):"Sem prazo"}</span></div>`}

function renderDashboard(){const cash=cashTotal(),assets=assetsTotal(),debts=debtsTotal(),nw=netWorth(),growth=snapshotGrowth();document.getElementById("heroNetWorth").textContent=brl(nw);document.getElementById("heroFreeCash").textContent=brl(freeCash());document.getElementById("heroReserved").textContent=brl(reservedCash());document.getElementById("heroInvested").textContent=brl(assets);document.getElementById("heroDebts").textContent=brl(debts);const gd=document.getElementById("heroGrowth");gd.className="hero-delta"+(growth===null?"":growth>=0?" positive":" negative");gd.textContent=growth===null?"Salve uma fotografia mensal para comparar":`${growth>=0?"+":""}${brl(growth)} desde a última fotografia`;document.getElementById("metricCash").textContent=brl(cash);document.getElementById("metricAssets").textContent=brl(assets);document.getElementById("metricDebts").textContent=brl(debts);document.getElementById("metricMonthResult").textContent=brl(monthResult());const goal=state.wealthGoal;document.getElementById("metricGoal").textContent=goal.target?`${Math.max(0,Math.min(100,nw/goal.target*100)).toFixed(0)}%`:"—";document.getElementById("metricGoalHint").textContent=goal.target?`${brl(goal.target)} de objetivo`:"Configure sua meta";
const parts=wealthParts(),max=Math.max(1,...parts.map(x=>Math.abs(x.value)));document.getElementById("wealthComposition").innerHTML=parts.map(x=>`<div class="composition-row"><div class="composition-name"><span>${x.icon}</span><strong>${x.name}</strong></div><div class="progress"><span style="width:${Math.abs(x.value)/max*100}%"></span></div><span>${(nw?Math.abs(x.value)/Math.max(1,Math.abs(nw))*100:0).toFixed(0)}%</span><strong class="${x.value<0?"amount-expense":""}">${brl(x.value)}</strong></div>`).join("");document.getElementById("liquidityRing").innerHTML=`<div class="liquidity-total"><span>Patrimônio líquido</span><strong>${brl(nw)}</strong></div><div class="liquidity-row"><span>Disponível agora</span><strong>${brl(freeCash())}</strong></div><div class="liquidity-row"><span>Reservado</span><strong>${brl(reservedCash())}</strong></div><div class="liquidity-row"><span>Preso em ativos</span><strong>${brl(assets)}</strong></div>`;
const accounts=state.accounts.map(a=>({a,b:accountBalance(a)})).sort((x,y)=>y.b-x.b).slice(0,5);document.getElementById("dashboardAccounts").innerHTML=accounts.length?accounts.map(({a,b})=>`<button class="location-row" data-account-history="${a.id}"><span class="location-icon">${esc(a.icon)}</span><span class="location-copy"><strong>${esc(a.name)}</strong><small>${esc(a.area)} · ${esc(a.liquidity==="free"?"Livre":"Reservado")}</small></span><strong class="${b>=0?"amount-income":"amount-expense"}">${brl(b)}</strong></button>`).join(""):"Nenhuma conta cadastrada.";
const alerts=[];const unassigned=sum(state.transactions.filter(t=>!t.accountId),t=>t.type==="income"?t.value:-t.value);if(unassigned!==0)alerts.push(["warning","Lançamentos sem conta",`${brl(Math.abs(unassigned))} líquidos ainda não têm localização definida.`]);const negative=state.accounts.filter(a=>accountBalance(a)<0);if(negative.length)alerts.push(["danger","Contas negativas",negative.map(a=>a.name).join(", ")]);const over=state.categories.filter(c=>c.type==="expense"&&c.monthlyBudget>0&&categorySpent(c)>c.monthlyBudget);if(over.length)alerts.push(["danger","Categorias acima do limite",over.map(c=>c.name).join(", ")]);if(nw>0&&freeCash()/nw<.2)alerts.push(["warning","Baixa liquidez","Menos de 20% do patrimônio está livre para uso imediato."]);const biggest=state.assets.slice().sort((a,b)=>b.currentValue-a.currentValue)[0];if(biggest&&nw>0&&biggest.currentValue/nw>.5)alerts.push(["warning","Patrimônio concentrado",`${biggest.name} representa mais de 50% do patrimônio líquido.`]);if(!alerts.length)alerts.push(["good","Estrutura sob controle","Nenhum alerta crítico identificado com os dados atuais."]);document.getElementById("dashboardAlerts").innerHTML=alerts.map(a=>`<div class="alert-card ${a[0]}"><strong>${a[1]}</strong><span>${a[2]}</span></div>`).join("");document.getElementById("dashboardHistory").innerHTML=chartHTML();document.getElementById("dashboardGoal").innerHTML=goalHTML()}

function fillFinanceFilters(){const cat=document.getElementById("financeCategoryFilter"),acc=document.getElementById("financeAccountFilter");const cv=cat.value||"all",av=acc.value||"all";cat.innerHTML=`<option value="all">Todas as categorias</option><option value="none">Sem categoria</option>${state.categories.slice().sort((a,b)=>a.name.localeCompare(b.name,"pt-BR")).map(c=>`<option value="${c.id}">${esc(c.icon)} ${esc(c.name)}</option>`).join("")}`;acc.innerHTML=`<option value="all">Todas as contas</option><option value="none">Sem conta</option>${state.accounts.slice().sort((a,b)=>a.name.localeCompare(b.name,"pt-BR")).map(a=>`<option value="${a.id}">${esc(a.icon)} ${esc(a.name)}</option>`).join("")}`;cat.value=[...cat.options].some(o=>o.value===cv)?cv:"all";acc.value=[...acc.options].some(o=>o.value===av)?av:"all"}
function renderFinances(){fillFinanceFilters();const m=document.getElementById("financeMonth").value||monthISO();const type=document.getElementById("financeTypeFilter").value,area=document.getElementById("financeAreaFilter").value,cat=document.getElementById("financeCategoryFilter").value,acc=document.getElementById("financeAccountFilter").value;const monthTx=monthTransactions(m),income=sum(monthTx.filter(t=>t.type==="income"),t=>t.value),expense=sum(monthTx.filter(t=>t.type==="expense"),t=>t.value);document.getElementById("financeIncome").textContent=brl(income);document.getElementById("financeExpense").textContent=brl(expense);document.getElementById("financeResult").textContent=brl(income-expense);const budgeted=state.categories.filter(c=>c.type==="expense"&&c.monthlyBudget>0),budget=sum(budgeted,c=>c.monthlyBudget),spent=sum(budgeted,c=>categorySpent(c,m));document.getElementById("financeBudgetRate").textContent=budget?`${(spent/budget*100).toFixed(0)}%`:"0%";const filtered=state.transactions.filter(t=>monthKey(t.date)===m&&(type==="all"||t.type===type)&&(area==="all"||t.area===area)&&(cat==="all"||(cat==="none"?!t.categoryId:t.categoryId===cat))&&(acc==="all"||(acc==="none"?!t.accountId:t.accountId===acc))).sort((a,b)=>dt(b)-dt(a));document.getElementById("transactionsTable").innerHTML=filtered.length?filtered.map(t=>`<tr><td><strong>${formatDate(t.date)}</strong><br><small>${t.time}</small></td><td>${esc(t.description)}</td><td><span class="pill">${esc(categoryName(t.categoryId))}</span></td><td>${esc(accountName(t.accountId))}</td><td>${t.type==="income"?"Receita":"Despesa"}</td><td class="${t.type==="income"?"amount-income":"amount-expense"}">${t.type==="income"?"+":"-"} ${brl(t.value)}</td><td><button class="icon-button" data-delete-transaction="${t.id}">✕</button></td></tr>`).join(""):`<tr><td colspan="7" class="empty">Nenhum lançamento encontrado.</td></tr>`;const bm=document.getElementById("budgetMonth").value||monthISO(),ba=document.getElementById("budgetAreaFilter").value;const cats=state.categories.filter(c=>c.type==="expense"&&(ba==="all"||c.area===ba)&&(c.monthlyBudget>0||categorySpent(c,bm)>0)).sort((a,b)=>{const ap=a.monthlyBudget?categorySpent(a,bm)/a.monthlyBudget:0,bp=b.monthlyBudget?categorySpent(b,bm)/b.monthlyBudget:0;return bp-ap});document.getElementById("budgetGrid").innerHTML=cats.length?cats.map(c=>{const actual=categorySpent(c,bm),limit=c.monthlyBudget,pct=limit?actual/limit*100:0,status=!limit?"neutral":pct>100?"over":pct>=80?"warning":"safe",label=!limit?"Sem limite":pct>100?"Estourado":pct>=80?"Atenção":"Dentro do limite";return `<article class="data-card glass budget-card ${status}" data-category-history="${c.id}" tabindex="0"><div class="card-top"><span class="card-icon">${esc(c.icon)}</span><div class="card-actions"><button class="icon-button" data-edit-category="${c.id}">✎</button><button class="icon-button" data-delete-category="${c.id}">✕</button></div></div><p class="eyebrow">${esc(c.area)}</p><h3>${esc(c.name)}</h3><strong class="big-value">${brl(actual)}</strong><div class="progress"><span style="width:${Math.min(100,pct)}%"></span></div><div class="card-footer"><span class="budget-status ${status}">${label}</span><strong>${limit?brl(limit):"—"}</strong></div></article>`}).join(""):`<div class="panel glass empty">Nenhuma categoria possui gasto ou limite neste mês. Use “Gerenciar categorias” para definir seus limites.</div>`}

function renderAccounts(){const total=cashTotal();document.getElementById("accountsTotal").textContent=brl(total);AREAS.forEach((ar,i)=>{const ids=["accountsPersonal","accountsCars","accounts3d"];document.getElementById(ids[i]).textContent=brl(sum(state.accounts.filter(a=>a.area===ar),accountBalance))});const un=sum(state.transactions.filter(t=>!t.accountId),t=>t.type==="income"?t.value:-t.value);document.getElementById("unassignedWarning").textContent=un?`${brl(Math.abs(un))} líquidos ainda estão sem conta definida.`:"";const items=state.accounts.map(a=>({a,b:accountBalance(a)})).sort((x,y)=>y.b-x.b);document.getElementById("accountsGrid").innerHTML=items.map(({a,b})=>{const tx=state.transactions.filter(t=>t.accountId===a.id),ins=sum(tx.filter(t=>t.type==="income"),t=>t.value)+sum(state.transfers.filter(t=>t.toAccountId===a.id),t=>t.value),outs=sum(tx.filter(t=>t.type==="expense"),t=>t.value)+sum(state.transfers.filter(t=>t.fromAccountId===a.id),t=>t.value);return `<article class="data-card glass" data-account-history="${a.id}" tabindex="0"><div class="card-top"><span class="card-icon">${esc(a.icon)}</span><div class="card-actions"><button class="icon-button" data-edit-account="${a.id}">✎</button><button class="icon-button" data-delete-account="${a.id}">✕</button></div></div><p class="eyebrow">${esc(a.area)} · ${a.liquidity==="free"?"Livre":"Reservado"}</p><h3>${esc(a.name)}</h3><strong class="big-value ${b>=0?"amount-income":"amount-expense"}">${brl(b)}</strong><div class="mini-grid"><div><span>Entradas</span><strong>${brl(ins)}</strong></div><div><span>Saídas</span><strong>${brl(outs)}</strong></div></div><div class="card-footer"><span>Inicial: ${brl(a.openingBalance)}</span><strong>Histórico →</strong></div></article>`}).join("");const positive=sum(items.filter(x=>x.b>0),x=>x.b);document.getElementById("accountDistribution").innerHTML=items.map(({a,b})=>{const pct=positive&&b>0?b/positive*100:0;return `<div class="distribution-row"><div class="composition-name"><span>${esc(a.icon)}</span><strong>${esc(a.name)}</strong></div><div class="progress"><span style="width:${pct}%"></span></div><span>${pct.toFixed(0)}%</span><strong>${brl(b)}</strong></div>`}).join("");const trs=state.transfers.slice().sort((a,b)=>dt(b)-dt(a)).slice(0,8);document.getElementById("transfersList").innerHTML=trs.length?trs.map(t=>`<div class="location-row"><span class="location-icon">↔</span><span class="location-copy"><strong>${esc(accountName(t.fromAccountId))} → ${esc(accountName(t.toAccountId))}</strong><small>${formatDate(t.date)} · ${t.time}</small></span><strong>${brl(t.value)}</strong></div>`).join(""):"Nenhuma transferência."}

function renderWealth(){const nw=netWorth(),cash=cashTotal(),at=assetsTotal(),debt=debtsTotal();document.getElementById("wealthNetWorth").textContent=brl(nw);document.getElementById("wealthCash").textContent=brl(cash);document.getElementById("wealthAssets").textContent=brl(at);document.getElementById("wealthDebts").textContent=brl(debt);const first=state.snapshots[0];document.getElementById("wealthVariation").textContent=first?`${nw-first.netWorth>=0?"+":""}${brl(nw-first.netWorth)}`:"—";document.getElementById("assetsGrid").innerHTML=state.assets.length?state.assets.slice().sort((a,b)=>b.currentValue-a.currentValue).map(a=>{const delta=a.currentValue-a.purchaseValue;return `<article class="data-card glass"><div class="card-top"><span class="card-icon">${esc(a.icon)}</span><div class="card-actions"><button class="icon-button" data-edit-asset="${a.id}">✎</button><button class="icon-button" data-delete-asset="${a.id}">✕</button></div></div><p class="eyebrow">${esc(a.area)} · ${esc(a.type)}</p><h3>${esc(a.name)}</h3><strong class="big-value">${brl(a.currentValue)}</strong><div class="mini-grid"><div><span>Investido</span><strong>${brl(a.purchaseValue)}</strong></div><div><span>Variação</span><strong class="${delta>=0?"amount-income":"amount-expense"}">${delta>=0?"+":""}${brl(delta)}</strong></div></div><div class="card-footer"><span>${formatDate(a.date)}</span><span>${esc(a.notes||"")}</span></div></article>`}).join(""):`<div class="panel glass empty">Nenhum ativo cadastrado. Contas bancárias não devem ser repetidas aqui.</div>`;document.getElementById("debtsGrid").innerHTML=state.debts.length?state.debts.slice().sort((a,b)=>b.currentBalance-a.currentBalance).map(d=>{const paid=Math.max(0,d.originalValue-d.currentBalance),pct=d.originalValue?paid/d.originalValue*100:0;return `<article class="data-card glass"><div class="card-top"><span class="card-icon">−</span><div class="card-actions"><button class="icon-button" data-edit-debt="${d.id}">✎</button><button class="icon-button" data-delete-debt="${d.id}">✕</button></div></div><p class="eyebrow">${esc(d.area)}${d.assetId?" · "+esc(asset(d.assetId)?.name||""):""}</p><h3>${esc(d.name)}</h3><strong class="big-value amount-expense">${brl(d.currentBalance)}</strong><div class="progress"><span style="width:${pct}%"></span></div><div class="mini-grid top-gap-small"><div><span>Parcela</span><strong>${brl(d.installment)}</strong></div><div><span>Quitado</span><strong>${pct.toFixed(0)}%</strong></div></div><div class="card-footer"><span>Vence dia ${d.dueDay||"—"}</span><span>${d.interest?d.interest+"% a.m.":"Sem juros informados"}</span></div></article>`}).join(""):`<div class="panel glass empty">Nenhuma dívida cadastrada.</div>`;document.getElementById("wealthHistory").innerHTML=chartHTML();document.getElementById("snapshotList").innerHTML=state.snapshots.slice().reverse().map(s=>`<div class="snapshot-row"><div><strong>${formatMonth(s.month)}</strong><br><span>Caixa ${brl(s.cash)} · Ativos ${brl(s.assets)} · Dívidas ${brl(s.debts)}</span></div><strong>${brl(s.netWorth)}</strong><button class="icon-button" data-delete-snapshot="${s.id}">✕</button></div>`).join("");const diffs=[];for(let i=1;i<state.snapshots.length;i++)diffs.push(state.snapshots[i].netWorth-state.snapshots[i-1].netWorth);if(state.snapshots.length)diffs.push(nw-state.snapshots[state.snapshots.length-1].netWorth);const avg=diffs.length?sum(diffs,x=>x)/diffs.length:null;document.getElementById("projectionGrid").innerHTML=avg===null?`<div class="empty">São necessárias pelo menos duas referências para projetar crescimento.</div>`:[3,6,12].map(m=>`<div class="projection-card"><span>Em ${m} meses</span><strong>${brl(nw+avg*m)}</strong></div>`).join("")+`<p class="projection-note">Estimativa baseada na média de ${brl(avg)} por mês. Não é garantia de resultado.</p>`;document.getElementById("wealthGoalPanel").innerHTML=goalHTML()}

function renderRoutine(){
  const status=document.getElementById("taskStatusFilter").value;
  const cat=document.getElementById("taskCategoryFilter").value;
  const list=state.tasks.filter(t=>(status==="all"||(status==="done"?t.done:!t.done))&&(cat==="all"||t.category===cat));
  const rank={high:0,medium:1,low:2};
  const pending=list.filter(t=>!t.done).sort((a,b)=>(rank[a.priority]-rank[b.priority])||(a.date||"9999").localeCompare(b.date||"9999"));
  const done=list.filter(t=>t.done);
  document.getElementById("pendingTasks").innerHTML=pending.length?pending.map(taskHTML).join(""):"Nenhuma tarefa pendente.";
  document.getElementById("doneTasks").innerHTML=done.length?done.map(taskHTML).join(""):"Nenhuma tarefa concluída.";
}
function renderAll(){renderDashboard();renderFinances();renderAccounts();renderWealth();renderRoutine()}

function saveSnapshot(){const month=monthISO(),data={month,netWorth:netWorth(),cash:cashTotal(),assets:assetsTotal(),debts:debtsTotal()};const existing=state.snapshots.find(s=>s.month===month);if(existing)Object.assign(existing,data);else state.snapshots.push({id:uid(),...data});state.snapshots.sort((a,b)=>a.month.localeCompare(b.month));save();renderAll();alert("Fotografia patrimonial salva.")}

function safeDeleteAccount(id){const a=account(id);if(state.transactions.some(t=>t.accountId===id)||state.transfers.some(t=>t.fromAccountId===id||t.toAccountId===id))return alert("Esta conta possui movimentações. Mova ou exclua os registros antes.");if(confirm(`Excluir ${a.name}?`)){state.accounts=state.accounts.filter(x=>x.id!==id);save();renderAll()}}

document.addEventListener("click",e=>{const p=e.target.closest("[data-page]")?.dataset.page;if(p)openPage(p);const jump=e.target.closest("[data-page-jump]")?.dataset.pageJump;if(jump)openPage(jump);if(e.target.closest("#quickAdd,#addTransactionBtn"))transactionForm();if(e.target.closest("#addCategoryBtn"))categoryForm();if(e.target.closest("#manageCategoriesBtn"))manageCategories();if(e.target.closest("#addAccountBtn"))accountForm();if(e.target.closest("#transferMoneyBtn"))transferForm();if(e.target.closest("#addAssetBtn"))assetForm();if(e.target.closest("#addDebtBtn"))debtForm();if(e.target.closest("#setWealthGoalBtn"))goalForm();if(e.target.closest("#saveSnapshotBtn"))saveSnapshot();if(e.target.closest("#addTaskBtn"))taskForm();if(e.target.matches("[data-close-modal]")||e.target.id==="modalBackdrop")closeModal();
const ch=e.target.closest("[data-category-history]")?.dataset.categoryHistory;if(ch&&!e.target.closest("[data-edit-category],[data-delete-category]"))categoryHistory(category(ch));const ah=e.target.closest("[data-account-history]")?.dataset.accountHistory;if(ah&&!e.target.closest("[data-edit-account],[data-delete-account]"))accountHistory(account(ah));
const editCat=e.target.closest("[data-edit-category]")?.dataset.editCategory;if(editCat)categoryForm(category(editCat));const delCat=e.target.closest("[data-delete-category]")?.dataset.deleteCategory;if(delCat&&confirm("Excluir categoria? Os lançamentos ficarão sem categoria.")){state.categories=state.categories.filter(c=>c.id!==delCat);state.transactions=state.transactions.map(t=>t.categoryId===delCat?{...t,categoryId:null}:t);save();renderAll()}
const editAcc=e.target.closest("[data-edit-account]")?.dataset.editAccount;if(editAcc)accountForm(account(editAcc));const delAcc=e.target.closest("[data-delete-account]")?.dataset.deleteAccount;if(delAcc)safeDeleteAccount(delAcc);
const editAsset=e.target.closest("[data-edit-asset]")?.dataset.editAsset;if(editAsset)assetForm(asset(editAsset));const delAsset=e.target.closest("[data-delete-asset]")?.dataset.deleteAsset;if(delAsset&&confirm("Excluir ativo?")){state.assets=state.assets.filter(a=>a.id!==delAsset);state.debts=state.debts.map(d=>d.assetId===delAsset?{...d,assetId:null}:d);save();renderAll()}
const editDebt=e.target.closest("[data-edit-debt]")?.dataset.editDebt;if(editDebt)debtForm(state.debts.find(d=>d.id===editDebt));const delDebt=e.target.closest("[data-delete-debt]")?.dataset.deleteDebt;if(delDebt&&confirm("Excluir dívida?")){state.debts=state.debts.filter(d=>d.id!==delDebt);save();renderAll()}
const delTx=e.target.closest("[data-delete-transaction]")?.dataset.deleteTransaction;if(delTx&&confirm("Excluir lançamento?")){state.transactions=state.transactions.filter(t=>t.id!==delTx);save();renderAll()}
const toggle=e.target.closest("[data-toggle-task]")?.dataset.toggleTask;if(toggle){const t=state.tasks.find(x=>x.id===toggle);if(t)t.done=!t.done;save();renderAll()}const delTask=e.target.closest("[data-delete-task]")?.dataset.deleteTask;if(delTask&&confirm("Excluir tarefa?")){state.tasks=state.tasks.filter(t=>t.id!==delTask);save();renderAll()}const delSnap=e.target.closest("[data-delete-snapshot]")?.dataset.deleteSnapshot;if(delSnap&&confirm("Excluir fotografia?")){state.snapshots=state.snapshots.filter(s=>s.id!==delSnap);save();renderAll()}});

document.addEventListener("keydown",e=>{if(!["Enter"," "].includes(e.key))return;const c=e.target.closest?.("[data-category-history]");if(c&&!e.target.closest("button")){e.preventDefault();categoryHistory(category(c.dataset.categoryHistory))}const a=e.target.closest?.("[data-account-history]");if(a&&!e.target.closest("button")){e.preventDefault();accountHistory(account(a.dataset.accountHistory))}});
["financeMonth","financeTypeFilter","financeAreaFilter","financeCategoryFilter","financeAccountFilter","budgetMonth","budgetAreaFilter","taskStatusFilter","taskCategoryFilter"].forEach(id=>document.getElementById(id)?.addEventListener("change",renderAll));
document.getElementById("themeToggle").onclick=()=>setTheme(state.theme==="dark"?"light":"dark");document.getElementById("themeToggleSettings").onclick=()=>setTheme(state.theme==="dark"?"light":"dark");document.getElementById("exportData").onclick=()=>{const blob=new Blob([JSON.stringify(state,null,2)],{type:"application/json"}),a=document.createElement("a");a.href=URL.createObjectURL(blob);a.download=`nexo-v4-cloud-backup-${todayISO()}.json`;a.click();URL.revokeObjectURL(a.href)};document.getElementById("importData").onchange=e=>{const file=e.target.files[0];if(!file)return;const r=new FileReader();r.onload=()=>{try{state=normalize(JSON.parse(r.result));save();setTheme(state.theme||"light");renderAll();alert("Backup importado e enviado para a nuvem.")}catch{alert("Arquivo inválido.")}};r.readAsText(file)};document.getElementById("clearData").onclick=()=>{if(confirm("Apagar todos os dados deste aplicativo e substituir também a versão da nuvem?")){state=normalize({});save();setTheme("light");renderAll()}};
document.getElementById("syncNow").onclick=async()=>{const ok=await syncCloudNow();if(ok)alert("Dados sincronizados.")};document.getElementById("logoutBtn").onclick=async()=>{await syncCloudNow();await supabase.auth.signOut()};
document.getElementById("showLogin").onclick=()=>setAuthMode("login");document.getElementById("showSignup").onclick=()=>setAuthMode("signup");document.getElementById("authForm").onsubmit=async e=>{e.preventDefault();if(!cloudConfigured)return;const email=document.getElementById("authEmail").value.trim(),password=document.getElementById("authPassword").value;document.getElementById("authSubmit").disabled=true;authMessage(authMode==="login"?"Entrando...":"Criando conta...","success");const result=authMode==="login"?await supabase.auth.signInWithPassword({email,password}):await supabase.auth.signUp({email,password,options:{emailRedirectTo:window.location.origin}});document.getElementById("authSubmit").disabled=false;if(result.error)return authMessage(result.error.message);if(authMode==="signup"&&!result.data.session)authMessage("Conta criada. Confirme o e-mail antes de entrar.","success")};
document.getElementById("forgotPassword").onclick=async()=>{const email=document.getElementById("authEmail").value.trim();if(!email)return authMessage("Digite seu e-mail primeiro.");const {error}=await supabase.auth.resetPasswordForEmail(email,{redirectTo:window.location.origin});authMessage(error?error.message:"E-mail de recuperação enviado.",error?"error":"success")};
window.addEventListener("online",()=>syncCloudNow());window.addEventListener("offline",()=>setSyncStatus("offline"));
document.getElementById("financeMonth").value=monthISO();document.getElementById("budgetMonth").value=monthISO();setTheme(state.theme||"light");renderAll();initializeCloud();
